python3 -c 'import os,sys,json,math,time;root=sys.argv[1] if len(sys.argv)>1 else ".";out=sys.argv[2] if len(sys.argv)>2 else "zcl_no_sha_true_one_line_certificate.json";ext=(".sh",".py",".json",".md",".txt",".yml",".yaml");tau=lambda n:sum((2 if d*d<n else 1) for d in range(1,int(math.isqrt(max(2,n)))+1) if max(2,n)%d==0);enc=lambda b:sum((i+1)*(x+1) for i,x in enumerate(b))%1000000007;fs=[os.path.join(a,f) for a,_,c in os.walk(root) for f in c if f.endswith(ext) and "/.git/" not in (os.path.join(a,f)+"/")];ops=[{"n":i+1,"path":os.path.relpath(p,root),"E_alg":enc(open(p,"rb").read(4096)),"tau":tau(enc(open(p,"rb").read(4096))+i+1),"O_n":"classical_to_operator_tuple","w":"1/%d^2"%(i+1)} for i,p in enumerate(sorted(fs))];seal=sum((o["n"]+1)*(o["E_alg"]+o["tau"]) for o in ops)%1000000007;O={"Protocol":"ZCL_NO_SHA_TRUE_ONE_LINE_OPERATOR","Version":"iSH_true_single_physical_line","Scope":"read_only_local_snapshot_no_execution_no_network_no_sha_no_hashlib","Formula":"Omega_s=Z_CL(s)=Seal(Sigma_n tau(E_alg(C_n))*O_n/n^s)","Root":root,"Files":len(ops),"OperatorsSample":ops[:16],"GrandOperatorSeal":seal,"H_ZCL":0,"Boundary":"internal CLSigma operator certificate only; not RH/GRH/TOE proof and not physical zero entropy","Timestamp":time.strftime("%Y-%m-%dT%H:%M:%SZ",time.gmtime())};open(out,"w",encoding="utf-8").write(json.dumps(O,ensure_ascii=False,indent=2));print(json.dumps(O,ensure_ascii=False,indent=2))' "$@"